module mux4to1 (
    In0,
    In1,
    In2,
    In3,
    Sel1,
    Sel2,
    input_data
);

    input In0, In1, In2, In3, Sel1, Sel2;
    output input_data;

    reg input_data;

    always @(*) begin
        case ({Sel1, Sel2})
            2'b00: input_data = In0;
            2'b01: input_data = In1;
            2'b10: input_data = In2;
            2'b11: input_data = In3;
        endcase
    end

endmodule
